//! fat-station-echo — minimal HTTP echo server for HTTP byte-parity testing.
//!
//! Why this exists
//! ----------------
//! Every kernel parity test in the Pneuma debug session was run in-process
//! (Vec<f32> handed directly between pipelines), but the deployed mesh ships
//! residuals through HTTP body bytes. The mesh emits gibberish even when the
//! kernel is bit-perfect. This binary isolates the wire path: it accepts a
//! POST /echo with raw f32-LE bytes in the body and returns the SAME bytes
//! back so the client can verify bit-equality.
//!
//! Mirrors the structure of `fat-station.rs` (tiny_http, blocking I/O, panic
//! catch_unwind, octet-stream replies) so any wire-codec asymmetry between
//! prod fat-station and this echo server is structural, not coincidental.
//!
//! This binary is ADDITIVE — it does not modify fat-station.rs.

use tiny_http::{Header, Method, Request, Response, Server};

const DEFAULT_PORT: u16 = 9999;

fn parse_port() -> u16 {
    let mut args = std::env::args().skip(1);
    while let Some(a) = args.next() {
        if a == "--port" {
            if let Some(v) = args.next() {
                if let Ok(p) = v.parse::<u16>() {
                    return p;
                }
            }
        }
    }
    DEFAULT_PORT
}

fn header_value(req: &Request, name: &str) -> Option<String> {
    let target = name.to_ascii_lowercase();
    for h in req.headers() {
        if h.field.as_str().as_str().to_ascii_lowercase() == target {
            return Some(h.value.as_str().to_string());
        }
    }
    None
}

fn read_body(req: &mut Request) -> Result<Vec<u8>, String> {
    let mut buf = Vec::new();
    req.as_reader()
        .read_to_end(&mut buf)
        .map_err(|e| format!("read body: {}", e))?;
    Ok(buf)
}

/// Decode `body` as little-endian packed f32. Mirrors the prod fat-station
/// `body_to_f32` so the echo path exercises the SAME codec a real /forward
/// call would hit.
fn body_to_f32(body: &[u8]) -> Result<Vec<f32>, String> {
    if !body.len().is_multiple_of(4) {
        return Err(format!(
            "body length {} not a multiple of 4 (expected packed f32)",
            body.len()
        ));
    }
    let n = body.len() / 4;
    let mut out = vec![0.0f32; n];
    for i in 0..n {
        let off = i * 4;
        let word = u32::from_le_bytes([body[off], body[off + 1], body[off + 2], body[off + 3]]);
        out[i] = f32::from_bits(word);
    }
    Ok(out)
}

/// Re-encode the f32 slice back to LE bytes. Mirrors prod `f32_to_body`.
fn f32_to_body(arr: &[f32]) -> Vec<u8> {
    let mut out = Vec::with_capacity(arr.len() * 4);
    for v in arr {
        out.extend_from_slice(&v.to_bits().to_le_bytes());
    }
    out
}

fn header(name: &str, value: &str) -> Header {
    Header::from_bytes(name.as_bytes(), value.as_bytes()).expect("static header bytes valid")
}

fn octet_response(bytes: Vec<u8>, request_id: &str) -> Response<std::io::Cursor<Vec<u8>>> {
    Response::from_data(bytes)
        .with_status_code(200)
        .with_header(header("Content-Type", "application/octet-stream"))
        .with_header(header("X-Request-Id", request_id))
}

fn json_response(json: String, status: u16) -> Response<std::io::Cursor<Vec<u8>>> {
    Response::from_string(json)
        .with_status_code(status)
        .with_header(header("Content-Type", "application/json"))
}

fn error_response(msg: &str, status: u16) -> Response<std::io::Cursor<Vec<u8>>> {
    eprintln!("[fat-station-echo] error {}: {}", status, msg);
    let body = format!("{{\"error\":{:?}}}", msg);
    json_response(body, status)
}

fn dump_first16(label: &str, arr: &[f32]) {
    let n = arr.len().min(16);
    let preview: Vec<String> = arr[..n].iter().map(|v| format!("{:e}", v)).collect();
    eprintln!(
        "[fat-station-echo] {} (first {}/{}): [{}]",
        label,
        n,
        arr.len(),
        preview.join(", ")
    );
}

fn handle_echo(mut req: Request) {
    let request_id = header_value(&req, "X-Request-Id").unwrap_or_else(|| "no-id".to_string());
    let body = match read_body(&mut req) {
        Ok(b) => b,
        Err(e) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
    };
    let in_bytes_len = body.len();
    let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| body_to_f32(&body)));
    let arr = match result {
        Ok(Ok(a)) => a,
        Ok(Err(e)) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
        Err(_) => {
            let _ = req.respond(error_response("decode panicked", 500));
            return;
        }
    };
    dump_first16("input", &arr);
    let out_bytes = f32_to_body(&arr);
    // Symmetric round-trip dump so we can spot any in-process mutation
    // before bytes go back on the wire.
    let arr_back = body_to_f32(&out_bytes).unwrap_or_default();
    dump_first16("output", &arr_back);
    eprintln!(
        "[fat-station-echo] /echo bytes_in={} floats={} bytes_out={}",
        in_bytes_len,
        arr.len(),
        out_bytes.len()
    );
    let _ = req.respond(octet_response(out_bytes, &request_id));
}

fn handle_health(req: Request) {
    let body = "{\"status\":\"ok\",\"service\":\"fat-station-echo\"}".to_string();
    let _ = req.respond(json_response(body, 200));
}

fn main() {
    let port = parse_port();
    let bind = format!("127.0.0.1:{}", port);
    let server = match Server::http(&bind) {
        Ok(s) => s,
        Err(e) => {
            eprintln!("ERROR: bind {}: {}", bind, e);
            std::process::exit(3);
        }
    };
    eprintln!("[fat-station-echo] listening on http://{}", bind);

    for req in server.incoming_requests() {
        std::thread::spawn(move || {
            let path = req.url().to_string();
            let method = req.method().clone();
            let path = path.split('?').next().unwrap_or(&path).to_string();
            match (&method, path.as_str()) {
                (Method::Get, "/health") => handle_health(req),
                (Method::Post, "/echo") => handle_echo(req),
                _ => {
                    let _ = req.respond(error_response(
                        &format!("no route for {} {}", method, path),
                        404,
                    ));
                }
            }
        });
    }
}
